import{_ as r,o as a,c as s,a2 as d}from"./chunks/framework.N6Nd-M9-.js";const t="/TCZY/assets/1000002917.CBbMbM6g.jpg",b=JSON.parse('{"title":"携号转网","description":"","frontmatter":{},"headers":[],"relativePath":"notes/产品知识/联通 5G/05-携号转网.md","filePath":"notes/产品知识/联通 5G/05-携号转网.md"}'),i={name:"notes/产品知识/联通 5G/05-携号转网.md"};function p(o,e,l,n,x,c){return a(),s("div",null,[...e[0]||(e[0]=[d('<h1 id="携号转网" tabindex="-1">携号转网 <a class="header-anchor" href="#携号转网" aria-label="Permalink to &quot;携号转网&quot;">​</a></h1><blockquote><p>号码不变，更换运营商。</p></blockquote><h2 id="目录" tabindex="-1">目录 <a class="header-anchor" href="#目录" aria-label="Permalink to &quot;目录&quot;">​</a></h2><div style="display:flex;flex-wrap:wrap;gap:12px;margin:15px 0;"><div style="background:rgba(102,126,234,0.06);border:1px solid rgba(102,126,234,0.15);padding:12px 20px;border-radius:12px;"><a class="tc-blue" href="#一什么是携号转网" style="text-decoration:none;font-weight:500;">📖 什么是携号转网</a></div><div style="background:rgba(34,197,94,0.06);border:1px solid rgba(34,197,94,0.15);padding:12px 20px;border-radius:12px;"><a class="tc-green" href="#二办理条件" style="text-decoration:none;font-weight:500;">✅ 办理条件</a></div><div style="background:rgba(239,68,68,0.06);border:1px solid rgba(239,68,68,0.15);padding:12px 20px;border-radius:12px;"><a class="tc-red" href="#三办理流程" style="text-decoration:none;font-weight:500;">📋 办理流程</a></div><div style="background:rgba(245,158,11,0.06);border:1px solid rgba(245,158,11,0.15);padding:12px 20px;border-radius:12px;"><a class="tc-orange" href="#四注意事项" style="text-decoration:none;font-weight:500;">⚠️ 注意事项</a></div><div style="background:rgba(59,130,246,0.06);border:1px solid rgba(59,130,246,0.15);padding:12px 20px;border-radius:12px;"><a href="#五常见问题" style="color:#3b82f6;text-decoration:none;font-weight:500;">❓ 常见问题</a></div></div><h2 id="一、什么是携号转网" tabindex="-1">一、什么是携号转网 <a class="header-anchor" href="#一、什么是携号转网" aria-label="Permalink to &quot;一、什么是携号转网&quot;">​</a></h2><p><strong>携号转网</strong>是指电话号码的持有人不再使用原运营商的电信服务，而想加入另一个电信运营商时，可以<strong>不改变原来的电话号码</strong>，将这个电话号码转入另一个运营商的旗下。</p><p>简单来说，就是消费者可以在<strong>不更换手机号码</strong>的情况下，<strong>更换自己的电信运营商</strong>，享受不同运营商提供的各种服务。</p><p><img src="'+t+'" alt="携号转网"></p><h3 id="适用范围" tabindex="-1">适用范围 <a class="header-anchor" href="#适用范围" aria-label="Permalink to &quot;适用范围&quot;">​</a></h3><div style="display:flex;flex-wrap:wrap;gap:15px;margin:15px 0;"><div style="flex:1;min-width:280px;background:rgba(34,197,94,0.06);border:1px solid rgba(34,197,94,0.15);padding:20px;border-radius:12px;"><p class="tc-green tc-bold tc-center" style="font-size:18px;margin:0 0 15px 0;">✅ 支持转网</p><div style="display:flex;flex-direction:column;gap:8px;"><span class="tc-body" style="background:rgba(34,197,94,0.1);padding:10px 15px;border-radius:8px;font-size:14px;">📱 中国移动、中国联通、中国电信的个人手机号码</span><span class="tc-body" style="background:rgba(34,197,94,0.1);padding:10px 15px;border-radius:8px;font-size:14px;">📍 同一归属地之间互转</span></div></div><div style="flex:1;min-width:280px;background:rgba(239,68,68,0.06);border:1px solid rgba(239,68,68,0.15);padding:20px;border-radius:12px;"><p class="tc-red tc-bold tc-center" style="font-size:18px;margin:0 0 15px 0;">❌ 不支持转网</p><div style="display:flex;flex-direction:column;gap:8px;"><span class="tc-body" style="background:rgba(239,68,68,0.1);padding:10px 15px;border-radius:8px;font-size:14px;">📵 虚拟运营商号码（170、171、162、165、167等）</span><span class="tc-body" style="background:rgba(239,68,68,0.1);padding:10px 15px;border-radius:8px;font-size:14px;">🌍 跨地市转网</span><span class="tc-body" style="background:rgba(239,68,68,0.1);padding:10px 15px;border-radius:8px;font-size:14px;">🛰️ 卫星移动业务号码（1349、174等）</span><span class="tc-body" style="background:rgba(239,68,68,0.1);padding:10px 15px;border-radius:8px;font-size:14px;">🔗 物联网号码（146、148、149、140-144等）</span></div></div></div><h2 id="二、办理条件" tabindex="-1">二、办理条件 <a class="header-anchor" href="#二、办理条件" aria-label="Permalink to &quot;二、办理条件&quot;">​</a></h2><p>根据工信部《携号转网服务管理规定》，用户办理携号转网需同时满足以下条件：</p><div style="display:grid;grid-template-columns:repeat(auto-fit,minmax(280px,1fr));gap:12px;margin:15px 0;"><div style="background:rgba(102,126,234,0.06);border:1px solid rgba(102,126,234,0.15);padding:15px;border-radius:12px;"><p class="tc-blue tc-bold" style="margin:0;font-size:16px;">✅ 实名登记</p><p class="tc-muted" style="margin:8px 0 0 0;font-size:14px;">号码已在原运营商办理真实身份信息登记。</p></div><div style="background:rgba(34,197,94,0.06);border:1px solid rgba(34,197,94,0.15);padding:15px;border-radius:12px;"><p class="tc-green tc-bold" style="margin:0;font-size:16px;">✅ 正常使用</p><p class="tc-muted" style="margin:8px 0 0 0;font-size:14px;">号码处于正常使用状态（非挂失、停机等）。</p></div><div style="background:rgba(239,68,68,0.06);border:1px solid rgba(239,68,68,0.15);padding:15px;border-radius:12px;"><p class="tc-red tc-bold" style="margin:0;font-size:16px;">✅ 结清费用</p><p class="tc-muted" style="margin:8px 0 0 0;font-size:14px;">与原运营商结清所有已出账电信费用，如有未出账费用需约定缴费方式。</p></div><div style="background:rgba(59,130,246,0.06);border:1px solid rgba(59,130,246,0.15);padding:15px;border-radius:12px;"><p class="tc-bold" style="margin:0;font-size:16px;color:#3b82f6;">✅ 无合约限制</p><p class="tc-muted" style="margin:8px 0 0 0;font-size:14px;">与原运营商无在网约定期限限制的协议，或已解除在网期限限制。</p></div><div style="background:rgba(245,158,11,0.06);border:1px solid rgba(245,158,11,0.15);padding:15px;border-radius:12px;"><p class="tc-orange tc-bold" style="margin:0;font-size:16px;">✅ 满120日</p><p class="tc-muted" style="margin:8px 0 0 0;font-size:14px;">距离最近一次携号转网已满 <strong>120日</strong>。</p></div></div><h3 id="查询是否符合条件" tabindex="-1">查询是否符合条件 <a class="header-anchor" href="#查询是否符合条件" aria-label="Permalink to &quot;查询是否符合条件&quot;">​</a></h3><p>编辑短信发送至当前运营商客服热线：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>CXXZ#用户名#证件号码</span></span></code></pre></div><div style="display:flex;flex-wrap:wrap;gap:12px;margin:15px 0;"><div class="tc-center" style="flex:1;min-width:180px;background:rgba(102,126,234,0.06);border:1px solid rgba(102,126,234,0.15);padding:15px;border-radius:12px;"><p class="tc-muted" style="margin:0;font-size:14px;">中国移动</p><p class="tc-blue tc-bold" style="margin:8px 0 0 0;font-size:20px;">📞 10086</p><p class="tc-sm" style="margin:5px 0 0 0;color:#999;">发送至 10086</p></div><div class="tc-center" style="flex:1;min-width:180px;background:rgba(239,68,68,0.06);border:1px solid rgba(239,68,68,0.15);padding:15px;border-radius:12px;"><p class="tc-muted" style="margin:0;font-size:14px;">中国联通</p><p class="tc-red tc-bold" style="margin:8px 0 0 0;font-size:20px;">📞 10010</p><p class="tc-sm" style="margin:5px 0 0 0;color:#999;">发送至 10010</p></div><div class="tc-center" style="flex:1;min-width:180px;background:rgba(34,197,94,0.06);border:1px solid rgba(34,197,94,0.15);padding:15px;border-radius:12px;"><p class="tc-muted" style="margin:0;font-size:14px;">中国电信</p><p class="tc-green tc-bold" style="margin:8px 0 0 0;font-size:20px;">📞 10000</p><p class="tc-sm" style="margin:5px 0 0 0;color:#999;">发送至 10001</p></div></div><h2 id="三、办理流程" tabindex="-1">三、办理流程 <a class="header-anchor" href="#三、办理流程" aria-label="Permalink to &quot;三、办理流程&quot;">​</a></h2><h3 id="_3-1-标准办理流程" tabindex="-1">3.1 标准办理流程 <a class="header-anchor" href="#_3-1-标准办理流程" aria-label="Permalink to &quot;3.1 标准办理流程&quot;">​</a></h3><div style="display:flex;flex-direction:column;gap:15px;margin:20px 0;"><div style="display:flex;align-items:center;gap:15px;"><div class="tc-bold" style="background:#667eea;color:#fff;width:50px;height:50px;border-radius:50%;display:flex;align-items:center;justify-content:center;font-size:22px;flex-shrink:0;">1</div><div style="flex:1;background:#f8f9fa;padding:15px;border-radius:12px;border-left:4px solid #667eea;"><p class="tc-body tc-bold" style="margin:0;font-size:16px;">📱 查询携出资格</p><p class="tc-muted" style="margin:8px 0 0 0;font-size:14px;">发送短信 <code style="background:#e9ecef;padding:2px 8px;border-radius:4px;">CXXZ#用户名#证件号码</code> 至 <strong>原运营商客服</strong>。</p></div></div><div style="display:flex;align-items:center;gap:15px;"><div class="tc-bold" style="background:#22c55e;color:#fff;width:50px;height:50px;border-radius:50%;display:flex;align-items:center;justify-content:center;font-size:22px;flex-shrink:0;">2</div><div style="flex:1;background:#f8f9fa;padding:15px;border-radius:12px;border-left:4px solid #22c55e;"><p class="tc-body tc-bold" style="margin:0;font-size:16px;">🔑 获取携转授权码</p><p class="tc-muted" style="margin:8px 0 0 0;font-size:14px;">收到授权码后 <strong class="tc-red">60分钟内</strong> 使用，过期需重新申请。</p></div></div><div style="display:flex;align-items:center;gap:15px;"><div class="tc-bold" style="background:#ef4444;color:#fff;width:50px;height:50px;border-radius:50%;display:flex;align-items:center;justify-content:center;font-size:22px;flex-shrink:0;">3</div><div style="flex:1;background:#f8f9fa;padding:15px;border-radius:12px;border-left:4px solid #ef4444;"><p class="tc-body tc-bold" style="margin:0;font-size:16px;">🏢 前往新运营商办理</p><p class="tc-muted" style="margin:8px 0 0 0;font-size:14px;">携带身份证和授权码，到新运营商营业厅办理。</p></div></div><div style="display:flex;align-items:center;gap:15px;"><div class="tc-bold" style="background:#3b82f6;color:#fff;width:50px;height:50px;border-radius:50%;display:flex;align-items:center;justify-content:center;font-size:22px;flex-shrink:0;">4</div><div style="flex:1;background:#f8f9fa;padding:15px;border-radius:12px;border-left:4px solid #3b82f6;"><p class="tc-body tc-bold" style="margin:0;font-size:16px;">📋 更换SIM卡（如需要）</p><p class="tc-muted" style="margin:8px 0 0 0;font-size:14px;">部分运营商可能需要更换为专用SIM卡。</p></div></div><div style="display:flex;align-items:center;gap:15px;"><div class="tc-bold" style="background:#f59e0b;color:#fff;width:50px;height:50px;border-radius:50%;display:flex;align-items:center;justify-content:center;font-size:22px;flex-shrink:0;">5</div><div style="flex:1;background:#f8f9fa;padding:15px;border-radius:12px;border-left:4px solid #f59e0b;"><p class="tc-body tc-bold" style="margin:0;font-size:16px;">✅ 生效使用</p><p class="tc-muted" style="margin:8px 0 0 0;font-size:14px;">携入72小时内可能影响部分业务（如彩铃、增值业务）。</p></div></div></div><div style="background:rgba(245,158,11,0.06);border-left:4px solid #f59e0b;padding:15px;border-radius:12px;margin-top:10px;"><p style="margin:0;font-size:14px;color:#92400e;"><strong>⚠️ 温馨提示：</strong>授权码有效期仅<strong>1小时</strong>，建议到新运营商营业厅后再申请，避免过期！</p></div><h3 id="_3-2-授权码获取方式" tabindex="-1">3.2 授权码获取方式 <a class="header-anchor" href="#_3-2-授权码获取方式" aria-label="Permalink to &quot;3.2 授权码获取方式&quot;">​</a></h3><div style="display:flex;flex-wrap:wrap;gap:12px;margin:15px 0;"><div style="flex:1;min-width:220px;background:rgba(102,126,234,0.06);border:1px solid rgba(102,126,234,0.15);padding:18px;border-radius:12px;"><p class="tc-blue tc-bold tc-center" style="margin:0;font-size:16px;">📱 中国移动</p><p class="tc-muted tc-sm tc-center" style="margin:10px 0 0 0;">指令：<code style="background:rgba(102,126,234,0.1);padding:2px 8px;border-radius:4px;">SQXZ#用户名#证件号码</code></p><p class="tc-body tc-center" style="margin:8px 0 0 0;font-size:14px;">发送至 <strong>10086</strong></p></div><div style="flex:1;min-width:220px;background:rgba(239,68,68,0.06);border:1px solid rgba(239,68,68,0.15);padding:18px;border-radius:12px;"><p class="tc-red tc-bold tc-center" style="margin:0;font-size:16px;">📱 中国联通</p><p class="tc-muted tc-sm tc-center" style="margin:10px 0 0 0;">指令：<code style="background:rgba(239,68,68,0.1);padding:2px 8px;border-radius:4px;">SQXZ#用户名#证件号码</code></p><p class="tc-body tc-center" style="margin:8px 0 0 0;font-size:14px;">发送至 <strong>10010</strong></p></div><div style="flex:1;min-width:220px;background:rgba(34,197,94,0.06);border:1px solid rgba(34,197,94,0.15);padding:18px;border-radius:12px;"><p class="tc-green tc-bold tc-center" style="margin:0;font-size:16px;">📱 中国电信</p><p class="tc-muted tc-sm tc-center" style="margin:10px 0 0 0;">指令：<code style="background:rgba(34,197,94,0.1);padding:2px 8px;border-radius:4px;">SQXZ#用户名#证件号码</code></p><p class="tc-body tc-center" style="margin:8px 0 0 0;font-size:14px;">发送至 <strong>10001</strong></p></div></div><div style="background:rgba(239,68,68,0.06);border:1px solid rgba(239,68,68,0.15);padding:15px;border-radius:12px;margin:15px 0;"><p class="tc-red tc-center" style="margin:0;font-size:15px;"><strong>⚠️ 注意：</strong>授权码有效期为 <strong>1小时</strong>，超过需重新申请。</p></div><h3 id="_3-3-办理所需材料" tabindex="-1">3.3 办理所需材料 <a class="header-anchor" href="#_3-3-办理所需材料" aria-label="Permalink to &quot;3.3 办理所需材料&quot;">​</a></h3><p>到目标运营商办理携入时，需提供：</p><div style="display:flex;flex-direction:column;gap:12px;margin:15px 0;"><div style="display:flex;align-items:center;gap:15px;"><div style="background:#667eea;color:#fff;width:45px;height:45px;border-radius:50%;display:flex;align-items:center;justify-content:center;font-size:20px;flex-shrink:0;">1</div><div style="flex:1;background:#f8f9fa;padding:15px;border-radius:12px;border-left:4px solid #667eea;"><p class="tc-body" style="margin:0;font-size:15px;"><strong>🪪 有效身份证件</strong>（与在原运营商登记的身份信息一致）</p></div></div><div style="display:flex;align-items:center;gap:15px;"><div style="background:#22c55e;color:#fff;width:45px;height:45px;border-radius:50%;display:flex;align-items:center;justify-content:center;font-size:20px;flex-shrink:0;">2</div><div style="flex:1;background:#f8f9fa;padding:15px;border-radius:12px;border-left:4px solid #22c55e;"><p class="tc-body" style="margin:0;font-size:15px;"><strong>🔑 有效的携出授权码</strong></p></div></div><div style="display:flex;align-items:center;gap:15px;"><div style="background:#ef4444;color:#fff;width:45px;height:45px;border-radius:50%;display:flex;align-items:center;justify-content:center;font-size:20px;flex-shrink:0;">3</div><div style="flex:1;background:#f8f9fa;padding:15px;border-radius:12px;border-left:4px solid #ef4444;"><p class="tc-body" style="margin:0;font-size:15px;"><strong>📱 申请携出号码对应的移动电话卡</strong></p></div></div></div><h2 id="四、注意事项" tabindex="-1">四、注意事项 <a class="header-anchor" href="#四、注意事项" aria-label="Permalink to &quot;四、注意事项&quot;">​</a></h2><h3 id="_4-1-转网前须知" tabindex="-1">4.1 转网前须知 <a class="header-anchor" href="#_4-1-转网前须知" aria-label="Permalink to &quot;4.1 转网前须知&quot;">​</a></h3><div style="display:grid;grid-template-columns:repeat(auto-fit,minmax(280px,1fr));gap:12px;margin:15px 0;"><div style="background:rgba(102,126,234,0.06);border:1px solid rgba(102,126,234,0.15);padding:18px;border-radius:12px;"><p class="tc-blue tc-bold" style="margin:0;font-size:16px;">💰 话费余额</p><p class="tc-muted" style="margin:10px 0 0 0;font-size:14px;">转网完成后，原运营商话费余额可按注销规则退还，具体咨询原运营商客服。</p></div><div style="background:rgba(34,197,94,0.06);border:1px solid rgba(34,197,94,0.15);padding:18px;border-radius:12px;"><p class="tc-green tc-bold" style="margin:0;font-size:16px;">🎁 积分/权益</p><p class="tc-muted" style="margin:10px 0 0 0;font-size:14px;">原运营商的积分、会员权益等将清零，建议提前兑换使用。</p></div><div style="background:rgba(239,68,68,0.06);border:1px solid rgba(239,68,68,0.15);padding:18px;border-radius:12px;"><p class="tc-red tc-bold" style="margin:0;font-size:16px;">🔗 绑定业务</p><p class="tc-muted" style="margin:10px 0 0 0;font-size:14px;">银行、支付宝、微信等绑定的手机号需重新验证。</p></div><div style="background:rgba(59,130,246,0.06);border:1px solid rgba(59,130,246,0.15);padding:18px;border-radius:12px;"><p class="tc-bold" style="margin:0;font-size:16px;color:#3b82f6;">💎 靓号协议</p><p class="tc-muted" style="margin:10px 0 0 0;font-size:14px;">如号码属于靓号，转网后可能需要重新签订靓号协议。</p></div></div><h3 id="_4-2-转网后影响" tabindex="-1">4.2 转网后影响 <a class="header-anchor" href="#_4-2-转网后影响" aria-label="Permalink to &quot;4.2 转网后影响&quot;">​</a></h3><div style="display:grid;grid-template-columns:repeat(auto-fit,minmax(280px,1fr));gap:12px;margin:15px 0;"><div style="background:rgba(245,158,11,0.06);border:1px solid rgba(245,158,11,0.15);padding:18px;border-radius:12px;"><p class="tc-orange tc-bold" style="margin:0;font-size:16px;">📨 短信接收</p><p class="tc-muted" style="margin:10px 0 0 0;font-size:14px;">转网生效后约 <strong>1小时内</strong>，可能无法正常接收短信（银行验证码等）。</p></div><div style="background:rgba(239,68,68,0.06);border:1px solid rgba(239,68,68,0.15);padding:18px;border-radius:12px;"><p class="tc-red tc-bold" style="margin:0;font-size:16px;">📲 APP登录</p><p class="tc-muted" style="margin:10px 0 0 0;font-size:14px;">部分APP可能因运营商信息变更需要重新验证。</p></div><div style="background:rgba(102,126,234,0.06);border:1px solid rgba(102,126,234,0.15);padding:18px;border-radius:12px;"><p class="tc-blue tc-bold" style="margin:0;font-size:16px;">📞 通话功能</p><p class="tc-muted" style="margin:10px 0 0 0;font-size:14px;">网络切换期间可能短时间影响正常通信。</p></div><div style="background:rgba(245,158,11,0.06);border:1px solid rgba(245,158,11,0.15);padding:18px;border-radius:12px;"><p class="tc-orange tc-bold" style="margin:0;font-size:16px;">⚙️ 业务办理</p><p class="tc-muted" style="margin:10px 0 0 0;font-size:14px;">转网后约 <strong>1小时内</strong> 无法登录运营商APP办理业务。</p></div></div><h3 id="_4-3-靓号特殊规定" tabindex="-1">4.3 靓号特殊规定 <a class="header-anchor" href="#_4-3-靓号特殊规定" aria-label="Permalink to &quot;4.3 靓号特殊规定&quot;">​</a></h3><div style="display:grid;grid-template-columns:repeat(auto-fit,minmax(280px,1fr));gap:12px;margin:15px 0;"><div style="background:rgba(239,68,68,0.06);border:1px solid rgba(239,68,68,0.15);padding:18px;border-radius:12px;"><p class="tc-red tc-bold" style="margin:0;font-size:16px;">⚠️ 协议期内转网</p><p class="tc-muted" style="margin:10px 0 0 0;font-size:14px;">需支付违约金（剩余合约期最低消费总额的90%左右）。</p></div><div style="background:rgba(34,197,94,0.06);border:1px solid rgba(34,197,94,0.15);padding:18px;border-radius:12px;"><p class="tc-green tc-bold" style="margin:0;font-size:16px;">✅ 协议期满后转网</p><p class="tc-muted" style="margin:10px 0 0 0;font-size:14px;">首次转出时可不执行靓号协议。</p></div><div style="background:rgba(102,126,234,0.06);border:1px solid rgba(102,126,234,0.15);padding:18px;border-radius:12px;"><p class="tc-blue tc-bold" style="margin:0;font-size:16px;">📝 转网后过户</p><p class="tc-muted" style="margin:10px 0 0 0;font-size:14px;">若后续再过户，将重新触发靓号协议。</p></div></div><h2 id="五、常见问题" tabindex="-1">五、常见问题 <a class="header-anchor" href="#五、常见问题" aria-label="Permalink to &quot;五、常见问题&quot;">​</a></h2><div style="display:flex;flex-direction:column;gap:12px;margin:15px 0;"><details style="background:rgba(102,126,234,0.06);border:1px solid rgba(102,126,234,0.15);border-radius:12px;overflow:hidden;"><summary class="tc-blue tc-bold" style="padding:15px 20px;cursor:pointer;font-size:16px;list-style:none;">❓ Q1：携号转网收费吗？</summary><div style="background:#f8f9fa;padding:15px 20px;margin:0 10px 10px 10px;border-radius:8px;"><p class="tc-body" style="margin:0;font-size:15px;"><strong>免费</strong>。携号转网服务本身不收取任何费用。</p></div></details><details style="background:rgba(34,197,94,0.06);border:1px solid rgba(34,197,94,0.15);border-radius:12px;overflow:hidden;"><summary class="tc-green tc-bold" style="padding:15px 20px;cursor:pointer;font-size:16px;list-style:none;">❓ Q2：转网后还能转回去吗？</summary><div style="background:#f8f9fa;padding:15px 20px;margin:0 10px 10px 10px;border-radius:8px;"><p class="tc-body" style="margin:0;font-size:15px;"><strong>可以</strong>。但需要距离上次转网满 <strong>120日</strong> 后才能再次办理。</p></div></details><details style="background:rgba(239,68,68,0.06);border:1px solid rgba(239,68,68,0.15);border-radius:12px;overflow:hidden;"><summary class="tc-red tc-bold" style="padding:15px 20px;cursor:pointer;font-size:16px;list-style:none;">❓ Q3：转网后号码归属地会变吗？</summary><div style="background:#f8f9fa;padding:15px 20px;margin:0 10px 10px 10px;border-radius:8px;"><p class="tc-body" style="margin:0;font-size:15px;"><strong>不会</strong>。携号转网只能在<strong>同一归属地</strong>内进行，号码归属地保持不变。</p></div></details><details style="background:rgba(59,130,246,0.06);border:1px solid rgba(59,130,246,0.15);border-radius:12px;overflow:hidden;"><summary class="tc-bold" style="color:#3b82f6;padding:15px 20px;cursor:pointer;font-size:16px;list-style:none;">❓ Q4：转网期间能正常使用手机吗？</summary><div style="background:#f8f9fa;padding:15px 20px;margin:0 10px 10px 10px;border-radius:8px;"><p class="tc-body" style="margin:0 0 8px 0;font-size:15px;"><strong>生效前</strong>：原移动电话卡正常使用，由原运营商提供服务。</p><p class="tc-body" style="margin:0 0 8px 0;font-size:15px;"><strong>生效时</strong>：网络切换期间可能短时间影响通信。</p><p class="tc-body" style="margin:0;font-size:15px;"><strong>生效后</strong>：新电话卡激活启用，由新运营商提供服务。</p></div></details><details style="background:rgba(245,158,11,0.06);border:1px solid rgba(245,158,11,0.15);border-radius:12px;overflow:hidden;"><summary class="tc-orange tc-bold" style="padding:15px 20px;cursor:pointer;font-size:16px;list-style:none;">❓ Q5：遇到运营商阻挠怎么办？</summary><div style="background:#f8f9fa;padding:15px 20px;margin:0 10px 10px 10px;border-radius:8px;"><p class="tc-body" style="margin:0 0 8px 0;font-size:15px;">可向以下渠道投诉：</p><p class="tc-muted" style="margin:0 0 5px 0;font-size:14px;">• 运营商客服热线（电信10000/10001，移动10086，联通10010）。</p><p class="tc-muted" style="margin:0 0 5px 0;font-size:14px;">• 工信部申诉受理机构。</p><p class="tc-muted" style="margin:0;font-size:14px;">• 互联网信息服务投诉平台。</p></div></details></div><h2 id="延伸阅读" tabindex="-1">延伸阅读 <a class="header-anchor" href="#延伸阅读" aria-label="Permalink to &quot;延伸阅读&quot;">​</a></h2><ul><li><a href="https://mp.weixin.qq.com/s/M62QgPDCrJjIHKJVHtI3ig" target="_blank" rel="noreferrer">【实用】携号转网，这份服务问答请收好！</a> — 工信部官方解答。</li></ul><p><em>文档整理时间：2026年5月12日</em></p>',39)])])}const f=r(i,[["render",p]]);export{b as __pageData,f as default};
